testbench:
`timescale 1ns/1ps
module tb;
  reg [2:0] in;
  wire [1:0] count;
  integer i;

  popcount3 dut(.in(in), .count(count));

  function [1:0] pop3;
    input [2:0] value;
    begin
      pop3 = value[0] + value[1] + value[2];
    end
  endfunction

  initial begin
    for (i = 0; i < 8; i = i + 1) begin
      in = i[2:0];
      #1;
      if (count !== pop3(i[2:0])) begin
        $display("FAIL in=%0b expected=%0d got=%0d", in, pop3(i[2:0]), count);
        $fatal(1);
      end
    end
    $display("PASS");
    $finish;
  end
endmodule

reference_rtl:
module popcount3(input [2:0] in, output [1:0] count);
  assign count = in[0] + in[1] + in[2];
endmodule
